import time
import random
class pet:
    def __init__(self, name, species, hapyns, hngr, thrs, hygn):
        self.name = name
        self.species = species
        self.hapyns = hapyns
        self.hngr = hngr
        self.thrs = thrs
        self.hygn = hygn
    def terminal(self):
        for i in range(100):
            print("")
        self.picture()
        print("Pet Name:", self.name)
        print("Species:", self.species)
        print("Happiness:", round((self.hapyns), 1))
        print("Hunger:", self.hngr)
        print("Thirst:", self.thrs)
        print("Hygiene:", self.hygn)
        print("Commands:")
        print("\"feed\"")
        print("\"play\"")
        print("\"give water\"")
        print("\"wash\"")
        print("\"nothing\"")
        print("\"rename\"")
        print("\"kill\"")
        print("")
    def feedpet(self):
        if self.hngr >= 98:
            print(self.name, " is full.")
            validcmd = 0
        else:
            self.hngr += random.randint(15, 35)
            print(self.name, " fed.")
    def play(self):
        self.hapyns += round((15 - (5 * (1 + (1 - (self.hngr / 100))))), 1)
        self.hapyns += round((15 - (5 * (1 + (1 - (self.hygn / 100))))), 1)
        self.hngr -= random.randint(2, 7)
        self.thrs -= random.randint(2, 7)
        print("Playing with ", self.name, "...")
    def wateringthedog(self):
        if self.thrs > 98:
            print(self.name, " is not thirsty.")
            validcmd = 0
        else:
            self.thrs += random.randint(15, 35)
            print(self.name, " drank.")
    def wash(self):
        self.hygn += random.randint(10, 15)
        print("Washing ", self.name)
